1	import {describe, it, expect} from "@jest/globals";
2	
3	import {convertInputNumberOptionsToNumericInput} from "./to-numeric-input";
4	
5	import type {PerseusInputNumberWidgetOptions} from "../../data-schema";
6	
7	const baseOptions: PerseusInputNumberWidgetOptions = {
8	    simplify: "required",
9	    size: "normal",
10	    value: "0",
11	};
12	
13	describe("convertInputNumberOptionsToNumericInput", () => {
14	    it("converts maxError to a number when present", () => {
15	        const options: PerseusInputNumberWidgetOptions = {
16	            ...baseOptions,
17	            inexact: true,
18	            maxError: "0.042",
19	        };
20	
21	        const result = convertInputNumberOptionsToNumericInput(options);
22	
23	        expect(result.answers).toHaveLength(1);
24	        expect(result.answers[0].maxError).toBe(0.042);
25	    });
26	
27	    it("converts maxError values in exponent notation", () => {
28	        const options: PerseusInputNumberWidgetOptions = {
29	            ...baseOptions,
30	            maxError: "42e-3",
31	            inexact: true,
32	        };
33	
34	        const result = convertInputNumberOptionsToNumericInput(options);
35	
36	        expect(result.answers).toHaveLength(1);
37	        expect(result.answers[0].maxError).toBe(0.042);
38	    });
39	
40	    it("leaves maxError undefined when undefined", () => {
41	        const options: PerseusInputNumberWidgetOptions = {
42	            ...baseOptions,
43	            maxError: undefined,
44	            inexact: true,
45	        };
46	
47	        const result = convertInputNumberOptionsToNumericInput(options);
48	
49	        expect(result.answers).toHaveLength(1);
50	        expect(result.answers[0].maxError).toBe(undefined);
51	    });
52	
