3	    PerseusNumericInputWidgetOptions,
4	} from "../../data-schema";
5	
6	type NumericInputAnswerPublicData = Pick<
7	    PerseusNumericInputAnswer,
8	    "answerForms" | "simplify" | "status"
9	>;
10	
11	/**
12	 * For details on the individual options, see the
13	 * PerseusNumericInputWidgetOptions type
14	 */
15	export type NumericInputPublicWidgetOptions = {
16	    labelText?: PerseusNumericInputWidgetOptions["labelText"];
17	    size: PerseusNumericInputWidgetOptions["size"];
18	    coefficient: PerseusNumericInputWidgetOptions["coefficient"];
19	    rightAlign?: PerseusNumericInputWidgetOptions["rightAlign"];
20	    answers: ReadonlyArray<NumericInputAnswerPublicData>;
21	};
22	
23	/**
24	 * This data from `answers` is used pre-scoring to give hints
25	 * to the learner regarding the format of accepted answers
26	 */
27	function getNumericInputAnswerPublicData(
28	    answer: PerseusNumericInputAnswer,
29	): NumericInputAnswerPublicData {
30	    const {answerForms, simplify, status} = answer;
31	    return {
32	        answerForms,
33	        simplify,
34	        status,
35	    };
36	}
37	
38	/**
39	 * Given a PerseusNumericInputWidgetOptions object, return a new object with only
40	 * the public options that should be exposed to the client.
41	 */
42	export function getNumericInputPublicWidgetOptions(
43	    options: PerseusNumericInputWidgetOptions,
44	): NumericInputPublicWidgetOptions {
45	    const {answers, ...publicWidgetOptions} = options;
46	    return {
47	        ...publicWidgetOptions,
48	        answers: answers.map(getNumericInputAnswerPublicData),
49	    };
50	}
