import {screen} from "@testing-library/react";
import {userEvent as userEventLib} from "@testing-library/user-event";

import {renderQuestion} from "../../widgets/__testutils__/renderQuestion";

import {getPromptJSON} from "./input-number-ai-utils";

import type {
    InputNumberWidget,
    PerseusRenderer,
    PerseusInputNumberUserInput,
} from "@khanacademy/perseus-core";
import type {UserEvent} from "@testing-library/user-event";

const question: PerseusRenderer = {
    content:
        "A sequence is defined recursively as follows:\n\n\n$\\qquad\\displaystyle{{a}_{n}}=-\\frac{1}{a_{n-1}-1} \n~~~~~~\\text{ with}\\qquad\\displaystyle{{a}_{0}}=\\frac{1}{2}\\,$\n\n\nFind the term $a_3$ in the sequence.\n\n[[\u2603 input-number 1]]",
    images: {},
    widgets: {
        // eslint-disable-next-line no-restricted-syntax
        "input-number 1": {
            graded: true,
            version: {
                major: 0,
                minor: 0,
            },
            static: false,
            type: "input-number",
            options: {
                maxError: 0.1,
                inexact: false,
                value: 0.5,
                simplify: "required",
                answerType: "number",
                size: "normal",
            },
            alignment: "default",
        } as InputNumberWidget,
    },
};

describe("InputNumber AI utils", () => {
    let userEvent: UserEvent;
    beforeEach(() => {
        userEvent = userEventLib.setup({
            advanceTimers: jest.advanceTimersByTime,
        });
    });

    it("it returns JSON with the expected format and fields", () => {
        const userInput: PerseusInputNumberUserInput = {
            currentValue: "123",
        };

        const widgetData: any = {
            simplify: "optional",
            answerType: "integer",
            userInput,
        };

        const resultJSON = getPromptJSON(widgetData);

        expect(resultJSON).toEqual({
            type: "input-number",
            options: {
                simplify: "optional",
                answerType: "integer",
            },
            userInput: {
                value: "123",
            },
        });
    });

    it("should get prompt json which matches the state of the UI", async () => {
        // Arrange
        const {renderer} = renderQuestion(question);

        // Act
        const input = "40";
        const textbox = screen.getByRole("textbox");
        await userEvent.click(textbox);
        await userEvent.type(textbox, input);
        const json = renderer.getPromptJSON();

        // Assert
        expect(json).toEqual({
            content:
                "A sequence is defined recursively as follows:\n\n\n$\\qquad\\displaystyle{{a}_{n}}=-\\frac{1}{a_{n-1}-1} \n~~~~~~\\text{ with}\\qquad\\displaystyle{{a}_{0}}=\\frac{1}{2}\\,$\n\n\nFind the term $a_3$ in the sequence.\n\n[[\u2603 input-number 1]]",
            widgets: {
                "input-number 1": {
                    type: "input-number",
                    options: {
                        simplify: "required",
                        answerType: "number",
                    },
                    userInput: {
                        value: "40",
                    },
                },
            },
        });
    });
});

import {describe, expect, test} from "@jest/globals";

import type {PerseusWidgetsMap, UserInputMap} from "@khanacademy/perseus-core";

import {
    scorePerseusItem,
    scorePerseusItemWithInputNumberAsNumericInput,
} from "./index";

interface TestCase {
    title: string;
    userInput: UserInputMap;
    widgets: PerseusWidgetsMap;
}

// NOTE: To add a test case to this list:
// - Go to https://console.cloud.google.com/logs
// - Search for "side-by-side" in the Perseus service
// - select "Copy > Copy as JSON"
// - `pbpaste | jq '.jsonPayload.metadata | {userInput: .inputNumberUserInputs, widgets: .inputNumberWidgets}'`
// TODO(LEMS-4085): Delete this test file.
const cases: TestCase[] = [
    {
        title: "when inexact = false",
        userInput: {
            "input-number 1": {
                currentValue: "6.336",
            },
            "input-number 2": {
                currentValue: "6.308",
            },
        },
        widgets: {
            "input-number 1": {
                options: {
                    value: 6.338,
                    answerType: "number",
                    rightAlign: false,
                    maxError: 0.1,
                    size: "normal",
                    simplify: "required",
                    inexact: false,
                },
                graded: true,
                static: false,
                version: {
                    minor: 0,
                    major: 0,
                },
                type: "input-number",
                alignment: "default",
            },
            "input-number 2": {
                type: "input-number",
                version: {
                    major: 0,
                    minor: 0,
                },
                static: false,
                alignment: "default",
                options: {
                    rightAlign: false,
                    maxError: 0.1,
                    size: "normal",
                    inexact: false,
                    simplify: "required",
                    value: 6.34,
                    answerType: "number",
                },
                graded: true,
            },
        },
    },
    {
        title: "when inexact = false and the correct answer has more than 9 decimal places",
        userInput: {
            "input-number 1": {
                currentValue: "1.123456789",
            },
        },
        widgets: {
            "input-number 1": {
                type: "input-number",
                version: {
                    major: 0,
                    minor: 0,
                },
                static: false,
                alignment: "default",
                options: {
                    rightAlign: false,
                    maxError: 0.1,
                    size: "normal",
                    inexact: false,
                    simplify: "required",
                    // rounds to 1.123456789
                    value: 1.1234567885,
                    answerType: "number",
                },
                graded: true,
            },
        },
    },
    {
        title: "when the user inputs a long decimal",
        userInput: {
            "input-number 1": {
                currentValue: "0.7692307692307",
            },
        },
        widgets: {
            "input-number 1": {
                options: {
                    maxError: 0.031,
                    simplify: "optional",
                    answerType: "number",
                    inexact: false,
                    size: "normal",
                    value: 0.7692307692307693,
                },
                graded: true,
                type: "input-number",
            },
        },
    },
];

describe("scoring with input-number converted to numeric-input", () => {
    test.each(cases)("$title", ({widgets, userInput}) => {
        const content = Object.keys(widgets)
            .map((id) => `[[\u2603 ${id}]]`)
            .join("");

        const scoringArgs: Parameters<typeof scorePerseusItem> = [
            {content, widgets, images: {}},
            userInput,
            "en",
        ];

        const officialScore = scorePerseusItem(...scoringArgs);
        const inniScore = scorePerseusItemWithInputNumberAsNumericInput(
            ...scoringArgs,
        );

        expect(inniScore).toEqual(officialScore);
    });
});

