4	/**
5	 * JSON describing an InputNumber widget. Intended for consumption by AI tools.
6	 * An InputNumber displays a text field where users can enter numbers in a
7	 * variety of formats: decimals, integers, fractions, mixed numbers,
8	 * percentages, and multiples of pi. The allowed formats are configurable by
9	 * the content creator.
10	 */
11	export type InputNumberPromptJSON = {
12	    type: "input-number";
13	
14	    /** The configuration of the widget, set by the content creator. */
15	    options: {
16	        /**
17	         * Indicates how answers in unsimplified form are scored.
18	         *
19	         * - "optional" means the answer can be unsimplified.
20	         * - "required" means an unsimplified answer is considered invalid,
21	         *   and the learner can try again without penalty.
22	         * - "enforced" means unsimplified answers are counted as incorrect.
23	         */
24	        simplify: string;
25	        /** The expected numeric form, e.g. "rational", "decimal" */
26	        answerType: string;
27	    };
28	
29	    /**
30	     * The current state of the widget user interface. Usually represents a
31	     * learner's attempt to answer a question.
32	     */
33	    userInput: {
34	        /** The text input by the user */
35	        value: string;
36	    };
37	};
38	
39	export const getPromptJSON = (
40	    widgetData: React.ComponentProps<typeof inputNumber.widget>,
41	): InputNumberPromptJSON => {
42	    return {
43	        type: "input-number",
44	        options: {
45	            simplify: widgetData.simplify,
46	            answerType: widgetData.answerType,
47	        },
48	        userInput: {
49	            value: widgetData.userInput.currentValue,
50	        },
51	    };
52	};
