import type {
    PerseusInputNumberAnswer,
    PerseusInputNumberWidgetOptions,
} from "../../data-schema";

type InputNumberAnswerPublicData = Pick<
    PerseusInputNumberAnswer,
    "answerForms" | "simplify" | "status"
>;

export type InputNumberPublicWidgetOptions = {
    labelText?: PerseusInputNumberWidgetOptions["labelText"];
    size: PerseusInputNumberWidgetOptions["size"];
    coefficient: PerseusInputNumberWidgetOptions["coefficient"];
    rightAlign?: PerseusInputNumberWidgetOptions["rightAlign"];
    answers: ReadonlyArray<InputNumberAnswerPublicData>;
};

function getInputNumberAnswerPublicData(
    answer: PerseusInputNumberAnswer,
): InputNumberAnswerPublicData {
    const {answerForms, simplify, status} = answer;
    return {answerForms, simplify, status};
}

export function getInputNumberPublicWidgetOptions(
    options: PerseusInputNumberWidgetOptions,
): InputNumberPublicWidgetOptions {
    const {answers, ...publicWidgetOptions} = options;
    return {
        ...publicWidgetOptions,
        answers: answers.map(getInputNumberAnswerPublicData),
    };
}

import {getInputNumberPublicWidgetOptions} from "./input-number-util";

import type {PerseusInputNumberWidgetOptions} from "../../data-schema";

describe("getInputNumberPublicWidgetOptions", () => {
    it("removes value", () => {
        const original: PerseusInputNumberWidgetOptions = {
            answers: [
                {
                    value: 42,
                    simplify: "optional",
                    status: "correct",
                    strict: true,
                    answerForms: [
                        "integer",
                        "decimal",
                        "proper",
                        "improper",
                        "mixed",
                    ],
                    message: "",
                },
            ],
            size: "normal",
            coefficient: false,
        };

        expect(getInputNumberPublicWidgetOptions(original)).toEqual({
            size: "normal",
            coefficient: false,
            answers: [
                {
                    simplify: "optional",
                    status: "correct",
                    answerForms: [
                        "integer",
                        "decimal",
                        "proper",
                        "improper",
                        "mixed",
                    ],
                },
            ],
        });
    });
});

import {getInputNumberPublicWidgetOptions} from "./input-number-util";

import type {InputNumberPublicWidgetOptions} from "./input-number-util";
import type {PerseusInputNumberWidgetOptions} from "../../data-schema";
import type {WidgetLogic} from "../logic-export.types";

export type InputNumberDefaultWidgetOptions = Pick<
    PerseusInputNumberWidgetOptions,
    "answers" | "size" | "coefficient" | "rightAlign"
>;

const defaultWidgetOptions: InputNumberDefaultWidgetOptions = {
    answers: [
        {
            value: 0,
            simplify: "required",
            status: "correct",
            strict: true,
            answerForms: ["integer", "decimal", "proper", "improper", "mixed"],
            message: "",
            maxError: 0,
        },
    ],
    size: "normal",
    coefficient: false,
    rightAlign: false,
};

const inputNumberWidgetLogic: WidgetLogic<
    PerseusInputNumberWidgetOptions,
    InputNumberPublicWidgetOptions
> = {
    name: "input-number",
    defaultWidgetOptions,
    defaultAlignment: "inline-block",
    accessible: false,
    getPublicWidgetOptions: getInputNumberPublicWidgetOptions,
};

export default inputNumberWidgetLogic;

