import type inputNumber from "../../widgets/input-number/input-number";
import type React from "react";

/**
 * JSON describing an InputNumber widget. Intended for consumption by AI tools.
 * An InputNumber displays a text field where users can enter numbers in a
 * variety of formats: decimals, integers, fractions, mixed numbers,
 * percentages, and multiples of pi. The allowed formats are configurable by
 * the content creator.
 */
export type InputNumberPromptJSON = {
    type: "input-number";

    /** The configuration of the widget, set by the content creator. */
    options: {
        /**
         * Indicates how answers in unsimplified form are scored.
         *
         * - "optional" means the answer can be unsimplified.
         * - "required" means an unsimplified answer is considered invalid,
         *   and the learner can try again without penalty.
         * - "enforced" means unsimplified answers are counted as incorrect.
         */
        simplify: string;
        /** The allowed numeric forms for the answer */
        answerForms: ReadonlyArray<string>;
    };

    /**
     * The current state of the widget user interface. Usually represents a
     * learner's attempt to answer a question.
     */
    userInput: {
        /** The text input by the user */
        value: string;
    };
};

export const getPromptJSON = (
    widgetData: React.ComponentProps<typeof inputNumber.widget>,
): InputNumberPromptJSON => {
    const firstAnswer = widgetData.answers?.[0];
    return {
        type: "input-number",
        options: {
            simplify: firstAnswer?.simplify ?? "",
            answerForms: firstAnswer?.answerForms ?? [],
        },
        userInput: {
            value: widgetData.userInput.currentValue,
        },
    };
};

import {screen} from "@testing-library/react";
import {userEvent as userEventLib} from "@testing-library/user-event";

import {renderQuestion} from "../../widgets/__testutils__/renderQuestion";

import {getPromptJSON} from "./input-number-ai-utils";

import type {
    InputNumberWidget,
    PerseusRenderer,
    PerseusInputNumberUserInput,
} from "@khanacademy/perseus-core";
import type {UserEvent} from "@testing-library/user-event";

const question: PerseusRenderer = {
    content:
        "A sequence is defined recursively as follows:\n\n\n$\\qquad\\displaystyle{{a}_{n}}=-\\frac{1}{a_{n-1}-1} \n~~~~~~\\text{ with}\\qquad\\displaystyle{{a}_{0}}=\\frac{1}{2}\\,$\n\n\nFind the term $a_3$ in the sequence.\n\n[[☃ input-number 1]]",
    images: {},
    widgets: {
        // eslint-disable-next-line no-restricted-syntax
        "input-number 1": {
            graded: true,
            version: {
                major: 0,
                minor: 0,
            },
            static: false,
            type: "input-number",
            options: {
                answers: [
                    {
                        value: 0.5,
                        simplify: "required",
                        status: "correct",
                        strict: true,
                        answerForms: [
                            "integer",
                            "decimal",
                            "proper",
                            "improper",
                            "mixed",
                        ],
                        message: "",
                        maxError: 0,
                    },
                ],
                size: "normal",
                coefficient: false,
            },
            alignment: "default",
        } as InputNumberWidget,
    },
};

describe("InputNumber AI utils", () => {
    let userEvent: UserEvent;
    beforeEach(() => {
        userEvent = userEventLib.setup({
            advanceTimers: jest.advanceTimersByTime,
        });
    });

    it("it returns JSON with the expected format and fields", () => {
        const userInput: PerseusInputNumberUserInput = {
            currentValue: "123",
        };

        const widgetData: any = {
            answers: [{simplify: "optional", answerForms: ["integer"]}],
            userInput,
        };

        const resultJSON = getPromptJSON(widgetData);

        expect(resultJSON).toEqual({
            type: "input-number",
            options: {
                simplify: "optional",
                answerForms: ["integer"],
            },
            userInput: {
                value: "123",
            },
        });
    });

    it("should get prompt json which matches the state of the UI", async () => {
        // Arrange
        const {renderer} = renderQuestion(question);

        // Act
        const input = "40";
        const textbox = screen.getByRole("textbox");
        await userEvent.click(textbox);
        await userEvent.type(textbox, input);
        const json = renderer.getPromptJSON();

        // Assert
        expect(json).toEqual({
            content:
                "A sequence is defined recursively as follows:\n\n\n$\\qquad\\displaystyle{{a}_{n}}=-\\frac{1}{a_{n-1}-1} \n~~~~~~\\text{ with}\\qquad\\displaystyle{{a}_{0}}=\\frac{1}{2}\\,$\n\n\nFind the term $a_3$ in the sequence.\n\n[[☃ input-number 1]]",
