47	function scoreInputNumber(
48	    // NOTE(benchristel): userInput can be undefined if the widget has never
49	    // been interacted with.
50	    userInput: PerseusInputNumberUserInput | undefined,
51	    rubric: PerseusInputNumberRubric,
52	    locale?: string,
53	): PerseusScore {
54	    if (userInput == null) {
55	        return {type: "invalid", message: null};
56	    }
57	
58	    if (rubric.answerType == null) {
59	        rubric.answerType = "number";
60	    }
61	
62	    // note(matthewc): this will get immediately parsed again by
63	    // `KhanAnswerTypes.number.convertToPredicate`, but a string is
64	    // expected here
65	    const stringValue = `${rubric.value}`;
66	    const val = KhanAnswerTypes.number.createValidatorFunctional(stringValue, {
67	        simplify: rubric.simplify,
68	        inexact: rubric.inexact || undefined,
69	        maxError: rubric.maxError,
70	        forms: inputNumberAnswerTypes[rubric.answerType].forms,
71	        // Pass locale-specific decimal separator to ensure that
72	        // we're properly parsing numbers according to the locale.
73	        ...(locale && {decimal_separator: getDecimalSeparator(locale)}),
74	    });
75	
76	    // We may have received TeX; try to parse it before grading.
77	    // If `currentValue` is not TeX, this should be a no-op.
78	    const currentValue = parseTex(userInput.currentValue);
79	
80	    const result = val(currentValue);
81	
82	    if (result.empty) {
83	        return {
84	            type: "invalid",
85	            message: result.message,
86	        };
87	    }
88	    return {
89	        type: "points",
90	        earned: result.correct ? 1 : 0,
91	        total: 1,
92	        message: result.message,
93	    };
94	}
