30	function getMaxError(
31	    inputNumberOptions: PerseusInputNumberWidgetOptionsV0,
32	): number | undefined {
33	    if (!inputNumberOptions.inexact) {
34	        return 0;
35	    }
36	
37	    if (inputNumberOptions.maxError == null) {
38	        return undefined;
39	    }
