45	// score-input-number.ts. I think this is okay because inputNumber is
46	// deprecated and the scoring logic will be removed as part of this project.
47	const mathFormatsForAnswerType: Record<
48	    PerseusInputNumberAnswerType,
49	    MathFormat[]
50	> = {
51	    number: ["integer", "decimal", "proper", "improper", "mixed"],
52	    decimal: ["decimal"],
53	    integer: ["integer"],
54	    rational: ["integer", "proper", "improper", "mixed"],
55	    improper: ["integer", "proper", "improper"],
56	    mixed: ["integer", "proper", "mixed"],
57	    percent: ["integer", "decimal", "proper", "improper", "mixed", "percent"],
58	    pi: ["pi"],
