61	function getAnswerForms(
62	    options: PerseusInputNumberWidgetOptionsV0,
63	): MathFormat[] {
64	    const value = Number(options.value);
65	    const {inexact} = options;
66	    const precision = 1e10;
67	    const rounded = Math.round(value * precision) / precision;
68	
69	    const answerType = options.answerType ?? "number";
70	    if (answerType === "number" && !inexact && !equalFloats(rounded, value)) {
71	        // Disallow decimal answers when the correct answer has more than 10
72	        // decimal places. This is for compatibility with legacy input-number
73	        // behavior.
74	        return ["proper", "improper", "mixed"];
75	    }
76	
77	    return mathFormatsForAnswerType[answerType];
78	}
