export function optional<T>(parseValue: Parser<T>): Parser<T | undefined> {
    return (rawValue, ctx) => {
        // Treat both `undefined` and `null` as absent. JSON serialization
        // converts `undefined` to absent and `NaN` to `null`, so round-tripping
        // through JSON can produce `null` where the original value was absent
        // or NaN.
        if (rawValue === undefined || rawValue === null) {
            return ctx.success(undefined);
        }
        return parseValue(rawValue, ctx);
    };
}

